def solve(data):
    if not isinstance(data, list) or not all(isinstance(item, dict) for item in data):
        raise ValueError("Input must be a list of dictionaries")

    results = []
    for entry in data:
        if 'fatal_injury' in entry and 'violence' in entry:
            results.append({
                'fatal_injury': entry['fatal_injury'],
                'violence': entry['violence'],
                'ratio': entry['fatal_injury'] / entry['violence'] if entry['violence'] > 0 else None
            })
        else:
            raise KeyError("Each entry must contain 'fatal_injury' and 'violence' keys")

    return results
